94	// Models advertised by gemini (cross-provider); the cross-pollination bug
95	// would surface a non-gemini provider hosting one of these.
96	const GEMINI_MODELS = new Set(['gemini-2.5-pro', 'gemini-2.5-flash', 'gemini-1.5-pro']);
97	const GEMINI_PROVIDERS = new Set(['gemini', 'google', 'vertex']);
98	
99	const QUEUE_READY = 4;
