119	function makeWorker(overrides: Partial<WorkerNode> = {}): WorkerNode {
120		return {
121			id: 'worker-drain-1',
122			kind: 'execute-loop',
123			state: 'running',
124			status: 'running',
125			harness: 'codex',
126			model: 'qwen3.6-35b',
127			currentBead: 'bead-001',
128			attempts: 0,
