138	function harnessBoundToLiveEndpoint(worker: WorkerNode): boolean {
139		const liveModels = new Set(ENDPOINT_FIXTURE.filter((e) => e.reachable).map((e) => e.model));
140		return liveModels.has(worker.model);
141	}
142	
143	function noGeminiCrossContamination(worker: WorkerNode): boolean {
144		const providerIsGemini = GEMINI_PROVIDERS.has(worker.harness.toLowerCase());
145		const modelIsGemini = GEMINI_MODELS.has(worker.model);
146		// A worker may be all-gemini or all-non-gemini, but never mixed.
147		return providerIsGemini === modelIsGemini;
148	}
149	
150	function attemptsMatchWorkDone(worker: WorkerNode): boolean {
151		return worker.attempts === worker.successes + worker.failures;
152	}
