154	async function installGraphqlMocks(
155		page: Page,
156		state: { workers: WorkerNode[]; dispatched: { count: number } }
157	) {
158		await page.route('/graphql', async (route) => {
159			const body = route.request().postDataJSON() as GqlBody;
160			const q = body.query;
161	
162			if (q.includes('NodeInfo')) {
163				await route.fulfill({
164					status: 200,
165					contentType: 'application/json',
166					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
167				});
168				return;
169			}
170			if (q.includes('Projects')) {
171				await route.fulfill({
172					status: 200,
173					contentType: 'application/json',
174					body: JSON.stringify({
175						data: { projects: { edges: [{ node: PROJECT }] } }
176					})
177				});
178				return;
179			}
180			if (q.includes('ProjectQueueSummary')) {
181				await route.fulfill({
182					status: 200,
183					contentType: 'application/json',
184					body: JSON.stringify({
185						data: {
186							queueSummary: { ready: QUEUE_READY, blocked: 0, inProgress: 0 }
187						}
188					})
189				});
190				return;
191			}
192			if (q.includes('ProviderStatuses')) {
193				await route.fulfill({
194					status: 200,
195					contentType: 'application/json',
196					body: JSON.stringify({
197						data: {
198							providerStatuses: ENDPOINT_FIXTURE,
199							harnessStatuses: [],
