205							}
206						}
207					})
208				});
209				return;
210			}
211			if (q.includes('WorkerDispatch') || q.includes('workerDispatch')) {
212				state.dispatched.count += 1;
213				const worker = makeWorker();
214				state.workers = [worker, ...state.workers];
215				await route.fulfill({
216					status: 200,
217					contentType: 'application/json',
