236						}
237					})
238				});
239				return;
240			}
241			if (q.includes('QueueAndWorkersSummary')) {
242				const running = state.workers.filter((w) => w.state === 'running').length;
243				await route.fulfill({
244					status: 200,
245					contentType: 'application/json',
246					body: JSON.stringify({
247						data: {
248							queueAndWorkersSummary: {
249								readyBeads: QUEUE_READY,
